{
  "name": "Georgia SHIP (State Health Insurance Assistance Program)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare beneficiaries, their families, and caregivers, including those with limited incomes, under age 65 with disabilities, or dually eligible for Medicare and Medicaid[3][2][8]",
    "asset_limits": "No asset limits or tests apply[2][8]",
    "other_requirements": ["Must be a Medicare beneficiary or their family/caregiver", "Georgia resident (implied for state program access)", "Services focus on Medicare-related issues[2][8]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased one-on-one counseling and assistance on Medicare (Parts A, B, C, D), Medigap, Medicaid, prescription drug programs, long-term care insurance, claims/billing resolution, appeals, fraud reporting via SMP, enrollment in plans and financial assistance programs (e.g., Medicare Savings Programs like QMB/SLMB/QI, Extra Help), information/referrals, public education presentations, and outreach events; no fixed dollar amounts or hours, provided via phone, face-to-face, or community sessions[2][3][5][6][8][10]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-866-552-4464 (Option 4 for counseling)[7][8]", "Website: https://aging.georgia.gov/georgia-ship (for info, webforms, requests)[7][8][10]", "Email: Regional examples like lplatter@accaging.org for local providers[5]", "In-person: Local sessions via area agencies on aging or community partners; request via phone[2][5]"],
    "processing_time": "No formal application or processing time; counseling provided upon contact as locally accessible services[2]",
    "waitlist": null,
    "forms": ["Webforms on https://aging.georgia.gov/georgia-ship for requests; no specific numbered application form required[10]"],
    "documents": ["Medicare card, Medicare Summary Notices, Explanation of Benefits, medical bills, or plan documents if available for counseling; not required to start[8][10]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide",
    "regional_variations": "Delivered through local partners like area agencies on aging (e.g., ACCA at 706-549-4850 in one region); contact methods and providers vary locally but services standardized[2][5]",
    "offices_or_providers": ["Administered by Georgia Department of Human Services Division of Aging Services; local via area agencies on aging and community partners[2][5]"]
  },
  "official_source": "https://aging.georgia.gov/georgia-ship",
  "gotchas": ["Not a financial aid or healthcare provider program—only free counseling/info, does not pay bills or provide insurance; not affiliated with insurers, does not sell plans; volunteer-based so availability depends on local counselors; people miss that it helps with applications for income-based programs like Extra Help (which have limits, e.g., SLMB up to $1,478/month single) but SHIP itself has no limits[4][8][10]", "Must request services; no automatic enrollment[8]"],
  "data_shape_notes": "no income/asset test; volunteer-based counseling only, not direct benefits; delivered via statewide network of local partners with standardized free services"
}

{
  "name": "Georgia Weatherization Assistance Program",
  "eligibility": {
    "age": null,
    "income_limits": "Household income at or below 200% of the Federal Poverty Level (FPL). Alternative qualification: receipt of Supplemental Security Income (SSI). Exact dollar amounts vary annually by FPL and household size; consult current FPL guidelines via local agency as specific table not detailed in sources. Priority given to elderly, households with disabilities, and families with children.[1][2][3][7]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Eligible home types: single-family, manufactured homes, appropriate multi-family units. Campers and non-stationary trailers ineligible.[1][3]", "Homeowners and renters eligible; renters require landlord agreement.[1]"]
  },
  "benefits": {
    "type": "service",
    "value": "No-cost home energy efficiency improvements based on energy audit results, including: air and duct sealing, wall/floor/attic insulation, HVAC system improvements, energy-efficient lighting, hot water tank/pipe insulation, water conservation devices. Does not cover pre-existing structural issues like roofing, walls, flooring holes, underpinning, or ceiling replacement.[1][3]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local community action agency by county (see gefa.georgia.gov for county-specific contacts).[4]", "Examples: CSRA EOA at (706) 945-1616 or www.csraeoa.org for application download (East Georgia counties); Action Pact via Savannahga.gov/4277 for Savannah/Chatham; Middle Georgia Community Action Agency (mgcaa.org) for Middle GA.[1][3][8]", "Phone, website download, in-person via local agency; mail possible through agency."],
    "processing_time": "Not specified; energy audit conducted if qualified, followed by measures installation. Varies by local agency.",
    "waitlist": "Due to high demand, there may be a waiting list.[4]",
    "forms": ["Agency-specific applications (e.g., download from www.csraeoa.org); check document for instructions per local provider.[1][3]"],
    "documents": ["Proof of income (to verify ≤200% FPL or SSI); required documents per local agency instructions.[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide via county-assigned local service providers (community action agencies).",
    "regional_variations": "Administered locally by different agencies (e.g., Action Pact in Savannah/Chatham, CSRA EOA in East GA, Middle GA CAA); varying contacts, offices, potential wait times by region.[1][3][4][8]",
    "offices_or_providers": ["County-specific list at gefa.georgia.gov/how-do-i-apply-weatherization (primary state source).[4]"]
  },
  "official_source": "https://gefa.georgia.gov/how-do-i-apply-weatherization",
  "gotchas": ["Renters need landlord permission.[1]", "Excludes structural repairs (e.g., roofs, walls, large flooring holes).[3]", "Priority for elderly/disabled/children, but no strict age cutoff—open to all qualifying low-income.[1][2]", "High demand leads to waitlists; not first-come-first-served.[4]", "Must use county-specific local agency, not statewide application.[4]"],
  "data_shape_notes": "Administered regionally by ~22 local community action agencies via GEFA; eligibility fixed at 200% FPL or SSI with priority tiers; services customized per home audit, not fixed dollar value."
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income at or below 125% of the federal poverty level. Exact dollar amounts vary annually by household size and are set by U.S. Department of Health and Human Services guidelines (not specified in sources for 2026; check current HHS poverty guidelines).",
    "asset_limits": null,
    "other_requirements": ["Unemployed and seeking to re-enter the workforce", "Poor employment prospects", "Priority to veterans/qualified spouses, individuals over 65, those with disabilities, low literacy/limited English proficiency, rural residents, homeless/at risk, or failed American Job Center services"]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time community service training positions averaging 20 hours per week at the highest of federal, state, or local minimum wage (e.g., $7.25/hour noted in one source); job training, educational opportunities, job placement assistance, annual physical exams, social service referrals; up to 1300 hours annual service; goal of transition to unsubsidized full-time employment.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact current providers: Legacy Link (specific contact not in results) and AARP Foundation SCSEP (contact via aarp.org/aarp-foundation/our-work/income/scsep/)", "Regional examples: Northwest Georgia - Keith Adams (706) 549-4850 or kadams@accaging.org; specific counties (Catoosa etc.) - Rachel Hunton at rhunton@accaging.org", "Georgia Department of Labor/WorkSource Georgia for job search assistance (websites: dol.georgia.gov, worksourcegeorgia.com)", "American Job Centers for employment assistance"],
    "processing_time": null,
    "waitlist": null,
    "forms": ["SCSEP Application (via regional providers like accaging.org)", "SCSEP Application Letter", "SCSEP Host Agency Interest Survey"],
    "documents": null
  },
  "geography": {
    "statewide": false,
    "restrictions": "Services available in majority of Georgia's 159 counties; specific counties served by providers (e.g., Catoosa, Chattooga, Cherokee, Dade, Douglas, Floyd, Gordon, Haralson, Paulding, Pickens, Polk, Walker, Whitfield via accaging.org)",
    "regional_variations": "Administered by multiple grantees/providers (e.g., Legacy Link, AARP Foundation, regional agencies like ACC Aging; different contact points and counties served by each; state agency (Georgia DHS) ended program July 1, 2025)",
    "offices_or_providers": ["Legacy Link", "AARP Foundation SCSEP", "ACC Aging (Northwest Georgia counties)", "WorkSource Georgia Career Centers"]
  },
  "official_source": "https://aging.georgia.gov/programs-and-services/senior-community-service-employment-program-scsep (notes state no longer offers; contact providers)",
  "gotchas": ["Georgia DHS ended state-administered SCSEP as of July 1, 2025; must contact private/non-profit providers like Legacy Link/AARP", "Not a permanent job but paid training (20 hrs/wk) with rotations to build skills", "Income test at 125% FPL strict; priority tiers affect enrollment", "Availability limited to specific counties per provider; high demand may imply waitlists though not specified"],
  "data_shape_notes": "State administration ended 7/1/2025; now provider-specific by region/county with multiple grantees; benefits fixed at ~20 hrs/wk minimum wage; priority enrollment tiers; no asset test or fixed dollar benefits"
}

{
  "name": "Georgia Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all residents of qualifying long-term care facilities regardless of financial status[5][7][8]",
    "asset_limits": "No asset limits or financial tests apply[5][7][8]",
    "other_requirements": ["Must be a resident of a long-term care facility including nursing homes, personal care homes, assisted living facilities, community living arrangements (CLAs), or intermediate care facilities for persons with intellectual and developmental disabilities (ICF/IDDs)[5][7][8]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Informal investigation and resolution of complaints on behalf of residents; routine facility visits to monitor conditions and talk to residents; education on long-term care issues and resident rights; advocacy for systemic changes; provision of resources and information on laws/policies governing facilities; promotion of resident/family/community involvement[5][6][7][8]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-866-552-4464 (select option 5)[8]", "Website: https://www.georgiaombudsman.org[7][8]"],
    "processing_time": "No formal application or processing time; services provided upon contact for complaint resolution or assistance[5][7][8]",
    "waitlist": null,
    "forms": [],
    "documents": ["No specific documents required; resident or representative permission needed for intervention[5][7]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services limited to residents in long-term care facilities statewide[5][7][8]",
    "regional_variations": "Administered through contracts with Area Agencies on Aging (AAA) and non-profit organizations, which may lead to different local providers or offices, but core services consistent statewide[6]",
    "offices_or_providers": ["Office of the State Long-Term Care Ombudsman within Georgia Department of Human Services’ Division of Aging Services; local services via AAAs and non-profits[4][6][8]"]
  },
  "official_source": "https://www.georgiaombudsman.org[7]",
  "gotchas": ["This is not a program that provides direct care, financial aid, or placement services—it's purely advocacy and complaint resolution for existing facility residents[5][7][8]", "Requires direct permission from resident or representative to intervene[5][7]", "Not for community-dwelling elderly; only for those in specified long-term care facilities[7][8]", "Certification and training details apply to ombudsman volunteers/staff, not residents seeking help[1][2][3]"],
  "data_shape_notes": "no income test; advocacy-only for residents of long-term care facilities; no formal eligibility application—contact-based; delivered via statewide network of AAAs/non-profits"
}
